let id = 1;

function makeProducts(subcategory, gender, names, prices, imgKey) {
  const imgs = imageMap[imgKey || subcategory] || imageMap["Shirts"];
  return names.map((name, i) => ({
    id: id++,
    name,
    category: gender,
    subcategory,
    price: prices[i % prices.length],
    rating: rnd(ratings),
    reviews: Math.floor(Math.random() * 2000) + 50,
    image: imgs[i % imgs.length],
    sizes: ["S", "M", "L", "XL"],
    description: `Premium quality ${name.toLowerCase()} crafted with care. Perfect for any occasion with a comfortable fit and stylish look.`,
    brand: rnd(["Zara", "H&M", "Myntra", "FabIndia", "Levi's", "Raymond", "Allen Solly", "Peter England"]),
  }));
}

